"import os\nfrom fastapi import FastAPI, Request\nfrom fastapi.staticfiles import StaticFiles\nfrom fastapi.responses import HTMLResponse\nfrom fastapi.templating import Jinja2Templates\nfrom pydantic import BaseModel\nimport json\n\napp = FastAPI(title=\"Apollo Studio Web Engine\")\n\n# Caminhos\nBASE_DIR = os.path.dirname(os.path.abspath(__file__))\nWEB_UI_DIR = os.path.join(BASE_DIR, \"web_ui\")\nSTATIC_DIR = os.path.join(WEB_UI_DIR, \"static\")\nTEMPLATES_DIR = os.path.join(WEB_UI_DIR, \"templates\")\n\n# Montando estáticos\napp.mount(\"/static\", StaticFiles(directory=STATIC_DIR), name=\"static\")\ntemplates = Jinja2Templates(directory=TEMPLATES_DIR)\n\n# Variável Global de Workspace (injetada pelo apollo_studio.py)\nCURRENT_WORKSPACE = \"Default\"\nCURRENT_WORKSPACE_PATH = \"\"\n\n@app.get(\"/\", response_class=HTMLResponse)\nasync def read_root(request: Request):\n    return templates.TemplateResponse(\"index.html\", {\"request\": request, \"workspace\": CURRENT_WORKSPACE})\n\n@app.get(\"/api/workspace\")\nasync def get_workspace_info():\n    \"\"\"Retorna dados básicos do workspace logado.\"\"\"\n    return {\n        \"name\": CURRENT_WORKSPACE,\n        \"path\": CURRENT_WORKSPACE_PATH\n    }\n\ndef start_server(workspace_name, workspace_path, port=8000):\n    \"\"\"Função chamada pelo apollo_studio.py para rodar o uvicorn.\"\"\"\n    global CURRENT_WORKSPACE, CURRENT_WORKSPACE_PATH\n    CURRENT_WORKSPACE = workspace_name\n    CURRENT_WORKSPACE_PATH = workspace_path\n    \n    import uvicorn\n    # log_level = \"warning\" evita spamar o terminal com acessos web\n    uvicorn.run(app, host=\"127.0.0.1\", port=port, log_level=\"warning\")\n\nif __name__ == \"__main__\":\n    start_server(\"Teste Local\", os.path.join(BASE_DIR, \"Workspaces\", \"Tutorial das Coisas\"))\n"